import json, sys
data = json.load\(sys.stdin\)
# Sadece Kasa tiplerini grupla \(PC hariç\)
stores = {}
for d in data:
    if d['deviceType'].upper\(\) == 'PC':
        continue
    sc = d['storeCode']
    if sc not in stores:
        stores[sc] = {'name': d['storeName'], 'kasalar': []}
    stores[sc]['kasalar'].append\({'type': d['deviceType'], 'online': d['isOnline']}\)

# Tüm kasaları offline olan mağazalar
print\('=== TÜM KASALARI OFFLINE MAĞAZALAR ==='\)
all_offline = [\(sc, s\) for sc, s in stores.items\(\) if all\(not k['online'] for k in s['kasalar']\)]
if all_offline:
    for sc, s in sorted\(all_offline\):
        print\(f'  {sc} {s[\\"name\\"]}: {len\(s[\\"kasalar\\"]\)} kasa hepsi offline'\)
else:
    print\('  YOK - hiçbir mağazanın tüm kasaları offline değil'\)

